package io.scanbot.sdk.reactnative.components.cropping_view

import android.content.Context
import android.graphics.Bitmap
import android.graphics.Color
import android.util.AttributeSet
import android.view.ViewGroup
import android.widget.FrameLayout
import androidx.core.graphics.createBitmap
import io.scanbot.sdk.core.ImageRef
import io.scanbot.sdk.core.ImageRotation
import io.scanbot.sdk.process.ImageProcessor
import io.scanbot.sdk.reactnative.extensions.layoutView
import io.scanbot.sdk.reactnative.extensions.sendEvent
import io.scanbot.sdk.reactnative.extensions.toPx
import io.scanbot.sdk.reactnative.models.CroppingViewCroppedAreaResult
import io.scanbot.sdk.reactnative.models.CroppingViewDefaultConfiguration.DEFAULT_ANCHOR_POINTS_COLOR
import io.scanbot.sdk.reactnative.models.CroppingViewDefaultConfiguration.DEFAULT_EDGE_COLOR
import io.scanbot.sdk.reactnative.models.CroppingViewDefaultConfiguration.DEFAULT_EDGE_ON_LINE_COLOR
import io.scanbot.sdk.ui.EditPolygonImageView
import io.scanbot.sdk.ui.MagnifierView
import io.scanbot.sdk.util.PolygonHelper
import io.scanbot.sdk_wrapper.document.extensions.toBitmapWithDecoding
import io.scanbot.sdk_wrapper.document.operations.doc_detection.SBDDocumentDetection
import io.scanbot.sdk_wrapper.extensions.toValidUriOrNull
import java.util.UUID
import java.util.concurrent.Executors

class ScanbotCroppingView(
    context: Context, attrs: AttributeSet?, defStyleAttr: Int, defStyleRes: Int
) : FrameLayout(context, attrs, defStyleAttr, defStyleRes) {

    constructor(context: Context) : this(context, null)
    constructor(context: Context, attrs: AttributeSet?) : this(context, attrs, 0)
    constructor(context: Context, attrs: AttributeSet?, defStyleAttr: Int) : this(
        context, attrs, defStyleAttr, 0
    )

    val editPolygonImageView = EditPolygonImageView(context, attrs)
    private val magnifierView = MagnifierView(context, attrs)

    private var bitmap: Bitmap? = null
    private val executor = Executors.newSingleThreadExecutor()

    init {
        layoutParams = ViewGroup.LayoutParams(
            LayoutParams.MATCH_PARENT,
            LayoutParams.MATCH_PARENT
        )
        setBackgroundColor(Color.BLACK)

        initCroppingView()

        addView(editPolygonImageView)
        addView(magnifierView)
    }

    private fun initCroppingView() {
        configureDefaults()
        editPolygonImageView.setImageBitmap(createBitmap(100, 100))
        editPolygonImageView.polygon = PolygonHelper.getFullPolygon()
        attachMagnifier()
    }

    private fun configureDefaults() {
        editPolygonImageView.setBackgroundColor(Color.BLACK)
        editPolygonImageView.setEdgeColor(DEFAULT_EDGE_COLOR)
        editPolygonImageView.setEdgeWidth(2.toPx(this.resources).toFloat())
        editPolygonImageView.setEdgeColorOnLine(DEFAULT_EDGE_ON_LINE_COLOR)
        editPolygonImageView.setAnchorPointsColor(DEFAULT_ANCHOR_POINTS_COLOR)
    }

    private fun attachMagnifier() {
        editPolygonImageView.setMagnifier(magnifierView)
        magnifierView.setupMagnifier(editPolygonImageView)
    }

    private fun setEditingBitmap(newBitmap: Bitmap) {
        bitmap = newBitmap

        editPolygonImageView.setImageBitmap(bitmap)
        attachMagnifier()

        detectPolygon()
    }

    fun setEditingImage(fileUri: String) {
        try {
            val imageUriAsBitmap = fileUri.toValidUriOrNull()
                ?.toBitmapWithDecoding(context.contentResolver)
                ?: throw Exception("File $fileUri could not be read")

            setEditingBitmap(imageUriAsBitmap)

        } catch (ex: Exception) {
            sendEvent(
                CroppingViewErrorEvent(
                    errorMessage = ex.message
                        ?: "An error has occurred while accessing file $fileUri"
                )
            )
        }
    }

    fun setEditingImageRef(uuid: String) {
        try {

            val imageBitmap =
                ImageRef.fromSerializedReference(UUID.fromString(uuid)).use { it.toBitmap() }

            if (imageBitmap != null) {
                setEditingBitmap(imageBitmap)
            } else {
                throw Exception("Could not retrieve bitmap from imageRef with $uuid")
            }
        } catch (ex: Exception) {
            sendEvent(
                CroppingViewErrorEvent(
                    errorMessage = ex.message
                        ?: "An error has occurred while creating imageRef with UUID $uuid"
                )
            )
        }
    }

    fun extractCroppedArea() {
        executor.execute {
            bitmap?.let {
                val imageRotation = when (editPolygonImageView.rotation.toInt() ) {
                    90, -270 -> ImageRotation.CLOCKWISE_90
                    -90, 270-> ImageRotation.COUNTERCLOCKWISE_90
                    180, -180 -> ImageRotation.CLOCKWISE_180
                    else -> ImageRotation.NONE
                }

                val croppedBitmap = ImageProcessor(it)
                    .crop(editPolygonImageView.polygon)
                    .rotate(imageRotation)
                    .processedBitmap()

                    if (croppedBitmap != null) {
                        sendEvent(
                            CroppingViewExtractCroppedAreaEvent(
                                CroppingViewCroppedAreaResult(
                                    polygon = editPolygonImageView.polygon,
                                    rotation = imageRotation,
                                    sourceImage = ImageRef.fromBitmap(croppedBitmap)
                                )
                            )
                        )
                        croppedBitmap.recycle()
                    } else {
                        sendEvent(
                            CroppingViewErrorEvent(
                                errorMessage = "An error has occurred while extracting cropped area"
                            )
                        )
                    }
            }
        }
    }

    fun detectPolygon() {
        executor.execute {
            bitmap?.let {
                try {
                    val documentDetectionResult = SBDDocumentDetection.detectDocumentOnBitmap(it)

                    editPolygonImageView.setLines(
                        documentDetectionResult.horizontalLinesNormalized,
                        documentDetectionResult.verticalLinesNormalized
                    )
                    editPolygonImageView.polygon = documentDetectionResult.pointsNormalized

                    editPolygonImageView.requestLayout()
                } catch (ex: Exception) {
                    sendEvent(
                        CroppingViewErrorEvent(
                            errorMessage = "An error has occurred while detecting document polygon: ${ex.message}"
                        )
                    )
                }
            }
        }
    }

    fun resetPolygon() {
        editPolygonImageView.polygon = PolygonHelper.getFullPolygon()
    }

    fun rotate(clockwise: Boolean) {
        if (clockwise) {
            editPolygonImageView.rotateClockwise()
        } else {
            editPolygonImageView.rotateCounterClockwise()
        }
    }

    fun removeAttachedListeners() {
        executor.shutdownNow()
    }

    override fun requestLayout() {
        super.requestLayout()
        post {
            layoutView()
        }
    }
}
